package com.hospital.management.model;/** Admission input; identity and bed details are resolved server-side. */public class AdmissionForm{private Long admissionId,patientId,doctorId,departmentId,appointmentId,bedId;private String expectedDischargeDate,admissionReason;public Long getAdmissionId(){return admissionId;}public void setAdmissionId(Long v){admissionId=v;}public Long getPatientId(){return patientId;}public void setPatientId(Long v){patientId=v;}public Long getDoctorId(){return doctorId;}public void setDoctorId(Long v){doctorId=v;}public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public Long getAppointmentId(){return appointmentId;}public void setAppointmentId(Long v){appointmentId=v;}public Long getBedId(){return bedId;}public void setBedId(Long v){bedId=v;}public String getExpectedDischargeDate(){return expectedDischargeDate;}public void setExpectedDischargeDate(String v){expectedDischargeDate=v;}public String getAdmissionReason(){return admissionReason;}public void setAdmissionReason(String v){admissionReason=v;}}
